    if not prices or k == 0:
        return 0
    n = len(prices)
    if k >= n // 2:
        # Unlimited transactions case
        profit = 0
        for i in range(1, n):
            if prices[i] > prices[i-1]:
            profit += prices[i] - prices[i-1]
        return profit
    # DP approach
    buy = [-float('inf')] * (k + 1)
    sell = [0] * (k + 1)
    for p in prices:
        for i in range(1, k + 1):
            sell[i] = max(sell[i], buy[i] + p)
            buy[i] = max(buy[i], sell[i-1] - p)
    return sell[k]

